(async () => {
  console.log("test");
  const allData = this.getValues();
  const temporaryData = allData.sm_item_balance.table_item_balance;
  const huData = allData.sm_item_balance.table_hu || [];
  const rowIndex = allData.sm_item_balance.row_index;
  const quantityUOM = allData.stock_movement[rowIndex].quantity_uom;
  const selectedUOM = allData.sm_item_balance.material_uom;

  let isValid = true;

  const allValid = temporaryData.every((item, idx) => {
    const valid =
      window.validationState && window.validationState[idx] !== false;
    return valid;
  });

  if (!allValid) {
    return;
  }

  const gdUOM = await db
    .collection("unit_of_measurement")
    .where({ id: quantityUOM })
    .get()
    .then((res) => res.data[0]?.uom_name || "");

  const materialId = allData.stock_movement[rowIndex].item_selection;
  let itemData = null;
  try {
    const itemResponse = await db
      .collection("Item")
      .where({ id: materialId })
      .get();
    itemData = itemResponse.data[0];
  } catch (error) {
    console.error("Error fetching item data:", error);
  }

  let processedTemporaryData = temporaryData;
  let processedHuData = huData;

  if (selectedUOM !== quantityUOM && itemData) {
    const tableUOMConversion = itemData.table_uom_conversion;
    const baseUOM = itemData.based_uom;

    const convertQuantityFromTo = (
      value,
      table_uom_conversion,
      fromUOM,
      toUOM,
      baseUOM,
    ) => {
      if (!value || fromUOM === toUOM) return value;

      let baseQty = value;
      if (fromUOM !== baseUOM) {
        const fromConversion = table_uom_conversion.find(
          (conv) => conv.alt_uom_id === fromUOM,
        );
        if (fromConversion && fromConversion.base_qty) {
          baseQty = value * fromConversion.base_qty;
        }
      }

      if (toUOM !== baseUOM) {
        const toConversion = table_uom_conversion.find(
          (conv) => conv.alt_uom_id === toUOM,
        );
        if (toConversion && toConversion.base_qty) {
          return Math.round((baseQty / toConversion.base_qty) * 1000) / 1000;
        }
      }

      return baseQty;
    };

    const balanceFields = [
      "block_qty",
      "reserved_qty",
      "unrestricted_qty",
      "qualityinsp_qty",
      "intransit_qty",
      "balance_quantity",
      "sm_quantity",
    ];

    processedTemporaryData = temporaryData.map((record) => {
      const convertedRecord = { ...record };
      balanceFields.forEach((field) => {
        if (convertedRecord[field]) {
          convertedRecord[field] = convertQuantityFromTo(
            convertedRecord[field],
            tableUOMConversion,
            selectedUOM,
            quantityUOM,
            baseUOM,
          );
        }
      });
      return convertedRecord;
    });

    processedHuData = huData.map((record) => {
      if (record.row_type !== "item") return { ...record };
      const convertedRecord = { ...record };
      ["item_quantity", "sm_quantity"].forEach((field) => {
        if (convertedRecord[field]) {
          convertedRecord[field] = convertQuantityFromTo(
            convertedRecord[field],
            tableUOMConversion,
            selectedUOM,
            quantityUOM,
            baseUOM,
          );
        }
      });
      return convertedRecord;
    });
  }

  // HU items the user actually wants to sm
  const filteredHuData = processedHuData.filter(
    (item) => item.row_type === "item" && parseFloat(item.sm_quantity || 0) > 0,
  );

  // Validate HU rows: sm_quantity must not exceed available item_quantity.
  // HU items are always treated as Unrestricted, so no category check applies.
  for (const huItem of filteredHuData) {
    const smQty = parseFloat(huItem.sm_quantity || 0);
    const availableQty = parseFloat(huItem.item_quantity || 0);
    if (smQty > availableQty) {
      const huHeader = huData.find(
        (row) =>
          row.row_type === "header" &&
          row.handling_unit_id === huItem.handling_unit_id,
      );
      const huName = huHeader?.handling_no || huItem.handling_unit_id;
      this.setData({
        error_message: `HU ${huName}: sm quantity (${smQty}) exceeds available (${availableQty}).`,
      });
      isValid = false;
      break;
    }
  }
  if (!isValid) return;

  const totalSmQuantity = processedTemporaryData
    .filter((item) => (item.sm_quantity || 0) > 0)
    .reduce((sum, item) => {
      const category_type = item.category ?? item.category_from;
      const quantity = item.sm_quantity || 0;

      if (quantity > 0) {
        let selectedField;

        switch (category_type) {
          case "Unrestricted":
            selectedField = item.unrestricted_qty;
            break;
          case "Reserved":
            selectedField = item.reserved_qty;
            break;
          case "Quality Inspection":
            selectedField = item.qualityinsp_qty;
            break;
          case "Blocked":
            selectedField = item.block_qty;
            break;
          case "In Transit":
            selectedField = item.intransit_qty;
            break;
          default:
            this.setData({ error_message: "Invalid category type" });
            isValid = false;
            return sum;
        }

        if (selectedField < quantity) {
          this.setData({
            error_message: `Quantity in ${category_type} is not enough.`,
          });
          isValid = false;
          return sum;
        }
      }

      return sum + quantity;
    }, 0);

  if (!isValid) return;

  const totalHuQuantity = filteredHuData.reduce(
    (sum, item) => sum + parseFloat(item.sm_quantity || 0),
    0,
  );
  const totalCombined = totalSmQuantity + totalHuQuantity;

  this.setData({
    [`stock_movement.${rowIndex}.total_quantity`]: totalCombined,
  });

  const currentBalanceIndex = this.getValues().balance_index || [];
  const rowsToUpdate = processedTemporaryData.filter(
    (item) => (item.sm_quantity || 0) > 0,
  );

  let updatedBalanceIndex = currentBalanceIndex.filter((item) => {
    return String(item.row_index) !== String(rowIndex);
  });

  rowsToUpdate.forEach((newRow) => {
    const newEntry = { ...newRow, row_index: rowIndex };
    delete newEntry.id;

    if (newEntry.dialog_manufacturing_date !== undefined) {
      newEntry.manufacturing_date = newEntry.dialog_manufacturing_date;
      delete newEntry.dialog_manufacturing_date;
    }
    if (newEntry.dialog_expired_date !== undefined) {
      newEntry.expired_date = newEntry.dialog_expired_date;
      delete newEntry.dialog_expired_date;
    }

    updatedBalanceIndex.push(newEntry);
  });

  // Convert HU items to balance-shape so they flow through the same persistence path.
  // sm_quantity carries the picked qty; category is always "Unrestricted" for HU items.
  const huAsBalanceRowsBase = filteredHuData.map((huItem) => ({
    material_id: huItem.material_id,
    location_id: huItem.location_id,
    batch_id: huItem.batch_id || null,
    balance_id: huItem.balance_id || "",
    sm_quantity: parseFloat(huItem.sm_quantity) || 0,
    category: "Unrestricted",
    handling_unit_id: huItem.handling_unit_id,
    plant_id: allData.issuing_operation_faci,
    organization_id: allData.organization_id,
    is_deleted: 0,
    expired_date: huItem.expired_date || null,
    manufacturing_date: huItem.manufacturing_date || null,
  }));

  huAsBalanceRowsBase.forEach((huRow) => {
    updatedBalanceIndex.push({ ...huRow, row_index: rowIndex });
  });

  // Detect duplicate serials across loose + HU within the same location/batch
  const serialLocationBatchMap = new Map();

  updatedBalanceIndex.forEach((entry) => {
    if (entry.serial_number && entry.serial_number.trim() !== "") {
      const serialNumber = entry.serial_number.trim();
      const locationId = entry.location_id || "no-location";
      const batchId = entry.batch_id || "no-batch";

      const combinationKey = `${serialNumber}|${locationId}|${batchId}`;

      if (!serialLocationBatchMap.has(combinationKey)) {
        serialLocationBatchMap.set(combinationKey, []);
      }

      serialLocationBatchMap.get(combinationKey).push({
        serialNumber: serialNumber,
        locationId: locationId,
        batchId: batchId,
      });
    }
  });

  const duplicates = [];
  for (const [combinationKey, entries] of serialLocationBatchMap.entries()) {
    if (entries.length > 1) {
      duplicates.push({
        combinationKey: combinationKey,
        serialNumber: entries[0].serialNumber,
      });
    }
  }

  if (duplicates.length > 0) {
    const duplicateMessages = duplicates
      .map((dup) => `• Serial Number "${dup.serialNumber}".`)
      .join("\n");

    this.$message.error(
      `Duplicate serial numbers detected in the same location/batch combination:\n\n${duplicateMessages}\n\nThe same serial number cannot be allocated multiple times to the same location and batch. Please remove the duplicates and try again.`,
    );
    return;
  }

  const formatLooseDetails = async (filteredData) => {
    const locationIds = [
      ...new Set(filteredData.map((item) => item.location_id)),
    ];

    const batchIds = [
      ...new Set(
        filteredData
          .map((item) => item.batch_id)
          .filter((batchId) => batchId != null && batchId !== ""),
      ),
    ];

    const locationPromises = locationIds.map(async (locationId) => {
      try {
        const resBinLocation = await db
          .collection("bin_location")
          .where({ id: locationId })
          .get();
        return {
          id: locationId,
          name:
            resBinLocation.data?.[0]?.bin_location_combine ||
            `Location ID: ${locationId}`,
        };
      } catch (error) {
        console.error(`Error fetching location ${locationId}:`, error);
        return { id: locationId, name: `${locationId} (Error)` };
      }
    });

    const batchPromises = batchIds.map(async (batchId) => {
      try {
        const resBatch = await db
          .collection("batch")
          .where({ id: batchId })
          .get();
        return {
          id: batchId,
          name: resBatch.data?.[0]?.batch_number || `Batch ID: ${batchId}`,
        };
      } catch (error) {
        console.error(`Error fetching batch ${batchId}:`, error);
        return { id: batchId, name: `${batchId} (Error)` };
      }
    });

    const [locations, batches] = await Promise.all([
      Promise.all(locationPromises),
      Promise.all(batchPromises),
    ]);

    const categoryMap = {
      Blocked: "BLK",
      Reserved: "RES",
      Unrestricted: "UNR",
      "Quality Inspection": "QIP",
      "In Transit": "INT",
    };

    const locationMap = locations.reduce((map, loc) => {
      map[loc.id] = loc.name;
      return map;
    }, {});

    const batchMap = batches.reduce((map, batch) => {
      map[batch.id] = batch.name;
      return map;
    }, {});

    return filteredData
      .map((item, index) => {
        const locationName = locationMap[item.location_id] || item.location_id;
        const qty = item.sm_quantity || 0;
        const category = item.category;
        const categoryAbbr = categoryMap[category] || category || "UNR";

        let itemDetail = `${
          index + 1
        }. ${locationName}: ${qty} ${gdUOM} (${categoryAbbr})`;

        if (itemData?.serial_number_management === 1 && item.serial_number) {
          itemDetail += `\nSerial: ${item.serial_number}`;
        }

        if (item.batch_id) {
          const batchName = batchMap[item.batch_id] || item.batch_id;
          itemDetail += `\n${
            itemData?.serial_number_management === 1 ? "Batch: " : "["
          }${batchName}${itemData?.serial_number_management === 1 ? "" : "]"}`;
        }

        if (item.remarks && item.remarks.trim() !== "") {
          itemDetail += `\nRemarks: ${item.remarks}`;
        }

        return itemDetail;
      })
      .join("\n");
  };

  const formatHuDetails = (filteredHuList) =>
    filteredHuList
      .map((item, index) => {
        const huHeader = huData.find(
          (row) =>
            row.row_type === "header" &&
            row.handling_unit_id === item.handling_unit_id,
        );
        const huName = huHeader?.handling_no || item.handling_unit_id;
        let detail = `${index + 1}. ${huName}: ${item.sm_quantity} ${gdUOM}`;
        if (item.batch_id) {
          detail += `\n   [Batch: ${item.batch_id}]`;
        }
        return detail;
      })
      .join("\n");

  const filteredLoose = processedTemporaryData.filter(
    (item) => (item.sm_quantity || 0) > 0,
  );
  const looseDetails = await formatLooseDetails(filteredLoose);
  const hasHu = filteredHuData.length > 0;
  const hasLoose = filteredLoose.length > 0;

  let formattedString;
  if (hasHu && hasLoose) {
    formattedString = `Total: ${totalCombined} ${gdUOM}\n\nLOOSE STOCK:\n${looseDetails}\n\nHANDLING UNIT:\n${formatHuDetails(
      filteredHuData,
    )}`;
  } else if (hasHu) {
    formattedString = `Total: ${totalHuQuantity} ${gdUOM}\n\nHANDLING UNIT:\n${formatHuDetails(
      filteredHuData,
    )}`;
  } else {
    formattedString = `Total: ${totalSmQuantity} ${gdUOM}\n\nDETAILS:\n${looseDetails}`;
  }

  // temp_qty_data carries loose + HU rows in balance shape; HU rows are
  // distinguishable via handling_unit_id. temp_hu_data carries the raw HU table
  // rows so the dialog can re-hydrate sm_quantity on next open.
  const cleanedLooseTempData = processedTemporaryData
    .filter((tempData) => tempData.sm_quantity > 0)
    .map((item) => {
      const cleaned = { ...item };
      if (cleaned.dialog_manufacturing_date !== undefined) {
        cleaned.manufacturing_date = cleaned.dialog_manufacturing_date;
        delete cleaned.dialog_manufacturing_date;
      }
      if (cleaned.dialog_expired_date !== undefined) {
        cleaned.expired_date = cleaned.dialog_expired_date;
        delete cleaned.dialog_expired_date;
      }
      return cleaned;
    });

  const combinedTempQty = [...cleanedLooseTempData, ...huAsBalanceRowsBase];

  this.setData({
    [`stock_movement.${rowIndex}.temp_qty_data`]:
      JSON.stringify(combinedTempQty),
    [`stock_movement.${rowIndex}.temp_hu_data`]: JSON.stringify(filteredHuData),
    [`stock_movement.${rowIndex}.stock_summary`]: formattedString,
  });

  const convertedBalanceIndex = updatedBalanceIndex.map((item) => {
    const converted = { ...item };

    const numericFields = [
      "unrestricted_qty",
      "reserved_qty",
      "qualityinsp_qty",
      "block_qty",
      "intransit_qty",
      "balance_quantity",
      "sm_quantity",
      "unit_price",
    ];

    numericFields.forEach((field) => {
      if (converted[field] !== null && converted[field] !== undefined) {
        const num = parseFloat(converted[field]) || 0;
        converted[field] = num.toFixed(3);
      }
    });

    if (converted.is_deleted !== undefined) {
      converted.is_deleted = converted.is_deleted ? 1 : 0;
    }

    return converted;
  });

  this.setData({ balance_index: [] });
  await new Promise((resolve) => setTimeout(resolve, 50));
  this.setData({ balance_index: convertedBalanceIndex });

  this.models["previous_material_uom"] = undefined;
  this.setData({ error_message: "" });
  this.closeDialog("sm_item_balance");
})();

const handleUOM = async (itemData, rowIndex) => {
  const altUoms = itemData.table_uom_conversion.map((data) => data.alt_uom_id);

  const uomPromises = altUoms.map((uomId) =>
    db.collection("unit_of_measurement").where({ id: uomId }).get(),
  );
  const uomResults = await Promise.all(uomPromises);
  const uomOptions = uomResults.map((res) => res.data[0]).filter(Boolean);

  this.setOptionData([`stock_movement.${rowIndex}.quantity_uom`], uomOptions);

  this.setData({
    [`stock_movement.${rowIndex}.uom_options`]: uomOptions,
  });
};

(async () => {
  const rowIndex = arguments[0].rowIndex;

  if (arguments[0].value) {
    const itemData = arguments[0]?.fieldModel?.item;

    if (itemData) {
      await handleUOM(itemData, rowIndex);

      this.setData({
        [`stock_movement.${rowIndex}.stock_summary`]: "",
        [`stock_movement.${rowIndex}.item_name`]: itemData.material_name,
        [`stock_movement.${rowIndex}.item_desc`]: itemData.material_desc,
        [`stock_movement.${rowIndex}.quantity_uom`]: itemData.based_uom,
        [`stock_movement.${rowIndex}.unit_price`]: itemData.purchase_unit_price,
      });
    } else {
      const tableSM = this.getValue("stock_movement");
      for (const [idx, sm] of tableSM.entries()) {
        this.setOptionData(
          [`stock_movement.${idx}.quantity_uom`],
          sm.uom_options,
        );
      }
    }
  } else {
    this.setData({
      [`stock_movement.${rowIndex}.requested_qty`]: 0,
      [`stock_movement.${rowIndex}.total_quantity`]: 0,
      [`stock_movement.${rowIndex}.quantity_uom`]: "",
      [`stock_movement.${rowIndex}.stock_summary`]: "",
      [`stock_movement.${rowIndex}.balance_id`]: "",
      [`stock_movement.${rowIndex}.temp_qty_data`]: "",
      [`stock_movement.${rowIndex}.item_name`]: "",
      [`stock_movement.${rowIndex}.item_desc`]: "",
    });
  }
})();

options.func:
class StockAdjuster {
    constructor(db) {
        this.db = db;
        this.categoryMap = {
            'Unrestricted': 'unrestricted_qty',
            'Quality Inspection': 'qualityinsp_qty',
            'Blocked': 'block_qty',
            'Reserved': 'reserved_qty',
            'In Transit': 'intransit_qty'
        };
    }

    async processStockAdjustment(db, self) {
        const stockMovementNo = self.getParamsVariables('stock_movement_no');
        const allData = self.getValues();

        try {
            // Fetch receiving stock movement
            const receivingResponse = await db.collection('stock_movement')
                .where({ stock_movement_no: stockMovementNo })
                .get();
                console.log("receivingResponse",receivingResponse)
            const receivingData = receivingResponse.data[0];
            const issuingStockMovementId = receivingData.movement_id;
            const receivingStockMovementId = receivingData.id;
            const receivingStockMovementPlantId = receivingData.plant_id;

            // Fetch issuing stock movement
            const issuingResponse = await db.collection('stock_movement')
                .where({ id: issuingStockMovementId })
                .get();
            const issuingData = issuingResponse.data[0];
            const issuingStockMovementPlantId = issuingData.plant_id;
            const issuingStockMovementNo = issuingData.stock_movement_no;

            // Process items and gather data
            const processedItems = this.processStockMovementItems(allData);

            // Update all tables
            const updateResults = await this.updateRelatedTables(
                processedItems,
                issuingStockMovementNo,
                stockMovementNo,
                issuingStockMovementPlantId,
                receivingStockMovementPlantId,
                receivingStockMovementId
            );

            return {
                receivingStockMovement: receivingData,
                issuingStockMovement: issuingData,
                ...updateResults
            };
        } catch (error) {
            console.error('Stock adjustment failed:', error);
            throw error;
        }
    }

    processStockMovementItems(allData) {
        const processedItems = [];

        // Step 1: Loop through stock_movement items
        allData.stock_movement.forEach(stockItem => {
            const itemDetails = {
                item_selection: stockItem.item_selection,
                category: stockItem.category || 'Unrestricted',
                location_id: stockItem.location_id,
                received_quantity: stockItem.received_quantity || 0,
                total_quantity: stockItem.total_quantity || 0
            };

            // Step 2: Filter balance_index based on item_selection
            const relatedBalances = allData.balance_index
                .filter(balance => balance.material_id === stockItem.item_selection)
                .map(balance => ({
                    material_id: balance.material_id,
                    balance_id: balance.balance_id,
                    category: itemDetails.category,
                    location_id: itemDetails.location_id,
                    received_quantity: itemDetails.received_quantity,
                    quantities: {
                        sm_quantity: balance.sm_quantity,
                        intransit_qty: balance.intransit_qty
                    }
                }));

            processedItems.push({
                itemDetails,
                balances: relatedBalances
            });
        });

        return processedItems;
    }

    async updateRelatedTables(processedItems, issuingStockMovementNo, stockMovementNo, 
                            issuingPlantId, receivingPlantId, receivingStockMovementId) {
        const results = {
            balanceUpdates: [],
            inventoryMovements: [],
            costingUpdates: []
        };

        for (const item of processedItems) {
            const { itemDetails, balances } = item;

            // Update balances
            for (const balance of balances) {
                // Update issuing balance
                const issuingBalanceUpdate = await this.updateIssuingBalance(
                    balance.balance_id,
                    balance.received_quantity
                );

                // Update or create receiving balance
                const receivingBalanceUpdate = await this.updateReceivingBalance(
                    balance.material_id,
                    receivingPlantId,
                    balance.location_id,
                    balance.received_quantity,
                    balance.category
                );

                results.balanceUpdates.push({
                    issuing: issuingBalanceUpdate,
                    receiving: receivingBalanceUpdate
                });

                // Record inventory movements
                const inventoryMovement = await this.recordInventoryMovement(
                    balance.material_id,
                    balance.received_quantity,
                    balance.category,
                    balance.location_id,
                    issuingStockMovementNo,
                    stockMovementNo,
                    issuingPlantId,
                    receivingPlantId,
                    receivingStockMovementId
                );
                results.inventoryMovements.push(inventoryMovement);

                // Update costing tables
                const costingUpdate = await this.updateCosting(
                    balance.material_id,
                    balance.received_quantity,
                    issuingPlantId,
                    receivingPlantId
                );
                results.costingUpdates.push(costingUpdate);
            }
        }
        // Update issuing stock movement status
        const allComplete = processedItems.every(item => 
            item.itemDetails.received_quantity === item.itemDetails.total_quantity
        );
        const status = allComplete ? 'completed' : 'in_progress';

        const issuingStockMovementResponse = await this.db.collection("stock_movement")
            .where({ stock_movement_no: issuingStockMovementNo })
            .get();
        const issuingStockMovement = issuingStockMovementResponse.data[0];

        if (issuingStockMovement) {
            await this.db.collection("stock_movement")
                .doc(issuingStockMovement.id)
                .update({
                    status: status,
                    update_time: new Date().toISOString()
                });

            const updatedIssuingStockMovementResponse = await this.db.collection("stock_movement")
                .doc(issuingStockMovement.id)
                .get();
            results.stockMovementUpdate = updatedIssuingStockMovementResponse.data[0];
        } else {
            throw new Error(`Issuing stock movement not found for stock_movement_no: ${issuingStockMovementNo}`);
        }

        return results;
        }

    async updateIssuingBalance(balanceId, receivedQuantity) {
        const collectionName = 'item_balance'; // Adjust if batch managed
        const balanceResponse = await this.db.collection(collectionName)
            .where({ id: balanceId })
            .get();
        const balanceData = balanceResponse.data[0];

        if (!balanceData) {
            throw new Error(`Balance not found for ID: ${balanceId}`);
        }

        const updateData = {
            intransit_qty: (balanceData.intransit_qty || 0) - receivedQuantity,
            balance_quantity: (balanceData.balance_quantity || 0) - receivedQuantity,
            update_time: new Date().toISOString()
        };

        await this.db.collection(collectionName)
            .doc(balanceId)
            .update(updateData);

        return { balanceId, ...updateData };
    }

    async updateReceivingBalance(materialId, plantId, locationId, receivedQuantity, category) {
        const collectionName = 'item_balance'; // Adjust if batch managed
        const categoryField = this.categoryMap[category];

        const balanceResponse = await this.db.collection(collectionName)
            .where({ material_id: materialId, plant_id: plantId, location_id: locationId })
            .get();
        const balanceData = balanceResponse.data[0];

        if (balanceData) {
            const updateData = {
                balance_quantity: (balanceData.balance_quantity || 0) + receivedQuantity,
                [categoryField]: (balanceData[categoryField] || 0) + receivedQuantity,
                update_time: new Date().toISOString()
            };

            await this.db.collection(collectionName)
                .doc(balanceData.id)
                .update(updateData);
            return { balanceId: balanceData.id, ...updateData };
        } else {
            const newBalanceData = {
                material_id: materialId,
                plant_id: plantId,
                location_id: locationId,
                balance_quantity: receivedQuantity,
                [categoryField]: receivedQuantity,
                unrestricted_qty: category === 'Unrestricted' ? receivedQuantity : 0,
                qualityinsp_qty: category === 'Quality Inspection' ? receivedQuantity : 0,
                block_qty: category === 'Blocked' ? receivedQuantity : 0,
                reserved_qty: category === 'Reserved' ? receivedQuantity : 0,
                intransit_qty: 0,
                create_time: new Date().toISOString(),
                update_time: new Date().toISOString()
            };

            const response = await this.db.collection(collectionName).add(newBalanceData);
            return { balanceId: response.data[0].id, ...newBalanceData };
        }
    }

    async recordInventoryMovement(materialId, quantity, category, locationId, 
                                issuingStockMovementNo, stockMovementNo, 
                                issuingPlantId, receivingPlantId, stockMovementId) {
        const outMovement = {
            trx_no: issuingStockMovementNo,
            movement_type: "Out",
            category: "In Transit",
            quantity: quantity,
            material_id: materialId,
            bin_location_id: locationId,
            plant_id: issuingPlantId,
            created_at: new Date(),
            stock_movement_id: stockMovementId
        };

        const inMovement = {
            trx_no: stockMovementNo,
            movement_type: "In",
            category: category,
            quantity: quantity,
            material_id: materialId,
            bin_location_id: locationId,
            plant_id: receivingPlantId,
            created_at: new Date(),
            stock_movement_id: stockMovementId
        };

        const [outResult, inResult] = await Promise.all([
            this.db.collection("inventory_movement").add(outMovement),
            this.db.collection("inventory_movement").add(inMovement)
        ]);

        return {
            out: outResult.data[0],
            in: inResult.data[0]
        };
    }

    async updateCosting(materialId, receivedQuantity, issuingPlantId, receivingPlantId) {
        const costingUpdates = {};

        // Fetch material data to determine costing method
        const materialResponse = await this.db.collection("Item")
            .where({ id: materialId })
            .get();
        const materialData = materialResponse.data[0];
        if (!materialData) {
            throw new Error(`Material not found for ID: ${materialId}`);
        }

        const organizationId = materialData.organization_id || 'default_org';

        if (materialData.material_costing_method === 'Weighted Average') {
            // Issuing plant (deduct)
            const waIssuingResponse = await this.db.collection("wa_costing_method")
                .where({ material_id: materialId, plant_id: issuingPlantId })
                .get();
            const waIssuingData = waIssuingResponse.data[0];
            if (waIssuingData) {
                const newQuantity = (waIssuingData.wa_quantity || 0) - receivedQuantity;
                if (newQuantity < 0) throw new Error("Insufficient WA quantity at issuing plant");
                await this.db.collection("wa_costing_method")
                    .doc(waIssuingData.id)
                    .update({ 
                        wa_quantity: newQuantity, 
                        updated_at: new Date() 
                    });
                costingUpdates.issuingWA = { 
                    id: waIssuingData.id, 
                    wa_quantity: newQuantity 
                };
            }

            // Receiving plant (add)
            const waReceivingResponse = await this.db.collection("wa_costing_method")
                .where({ material_id: materialId, plant_id: receivingPlantId })
                .get();
            const waReceivingData = waReceivingResponse.data[0];
            if (waReceivingData) {
                const newQuantity = (waReceivingData.wa_quantity || 0) + receivedQuantity;
                await this.db.collection("wa_costing_method")
                    .doc(waReceivingData.id)
                    .update({ 
                        wa_quantity: newQuantity, 
                        updated_at: new Date() 
                    });
                costingUpdates.receivingWA = { 
                    id: waReceivingData.id, 
                    wa_quantity: newQuantity 
                };
            } else {
                const newWAData = {
                    material_id: materialId,
                    plant_id: receivingPlantId,
                    wa_quantity: receivedQuantity,
                    wa_cost_price: waIssuingData?.wa_cost_price || 0, // Carry over cost price from issuing if exists
                    created_at: new Date(),
                    updated_at: new Date()
                };
                const newWAResponse = await this.db.collection("wa_costing_method").add(newWAData);
                costingUpdates.receivingWA = { 
                    id: newWAResponse.data[0].id, 
                    ...newWAData 
                };
            }
        } else if (materialData.material_costing_method === 'First In First Out') {
            // Issuing plant (deduct)
            const fifoIssuingResponse = await this.db.collection("fifo_costing_history")
                .where({ material_id: materialId, plant_id: issuingPlantId })
                .get();
            let fifoIssuingData = fifoIssuingResponse.data || [];
            if (fifoIssuingData.length && receivedQuantity > 0) {
                let remainingReduction = receivedQuantity;
                fifoIssuingData.sort((a, b) => a.fifo_sequence - b.fifo_sequence);

                for (const fifoRecord of fifoIssuingData) {
                    if (remainingReduction <= 0) break;

                    const available = fifoRecord.fifo_available_quantity;
                    const reduction = Math.min(available, remainingReduction);
                    const newAvailable = available - reduction;

                    await this.db.collection("fifo_costing_history")
                        .doc(fifoRecord.id)
                        .update({ 
                            fifo_available_quantity: newAvailable, 
                            updated_at: new Date() 
                        });
                    costingUpdates.issuingFIFO = costingUpdates.issuingFIFO || [];
                    costingUpdates.issuingFIFO.push({ 
                        id: fifoRecord.id, 
                        fifo_available_quantity: newAvailable 
                    });

                    remainingReduction -= reduction;
                }

                if (remainingReduction > 0) {
                    throw new Error("Insufficient FIFO quantity at issuing plant");
                }
            }

            // Receiving plant (add)
            const fifoReceivingResponse = await this.db.collection("fifo_costing_history")
                .where({ material_id: materialId, plant_id: receivingPlantId })
                .get();
            const fifoReceivingData = fifoReceivingResponse.data || [];
            let sequenceNumber = 1;
            if (fifoReceivingData.length) {
                const existingSequences = fifoReceivingData.map(doc => parseInt(doc.fifo_sequence || 0));
                sequenceNumber = Math.max(...existingSequences, 0) + 1;
            }

            // Get cost price from earliest issuing FIFO record if available
            const fifoCostPrice = fifoIssuingData.length ? 
                fifoIssuingData[0].fifo_cost_price : 
                0;

            const newFifoData = {
                fifo_cost_price: fifoCostPrice,
                fifo_initial_quantity: receivedQuantity,
                fifo_available_quantity: receivedQuantity,
                material_id: materialId,
                batch_id: materialData.item_isbatch_managed === '1' ? materialId : null,
                fifo_sequence: sequenceNumber,
                plant_id: receivingPlantId,
                organization_id: organizationId,
                created_at: new Date(),
                updated_at: new Date()
            };
            const newFifoResponse = await this.db.collection("fifo_costing_history").add(newFifoData);
            costingUpdates.receivingFIFO = { 
                id: newFifoResponse.data[0].id, 
                ...newFifoData 
            };
        }

        return costingUpdates;
    }
}

